        for (int j = 0; j < amount+1; j++) {
            dp[0][j] = 1;
        }
        for (int i = 1; i < coinsSize+1; i++) {
            for (int j = 1; j < amount+1; j++) {
                if (j >= coins[i-1]) {
                    dp[i][j] = dp[i-1][j] + dp[i][j-coins[i-1]];
